sql:
SELECT COUNT(*) 
FROM program_inquiries 
WHERE program_id = 1 AND student_name LIKE 'John%';

SELECT COUNT(enrollment_id) AS active_enrollment_count
FROM program_enrollments
WHERE status = 'active';

SELECT COUNT(enrollment_id) AS enrollment_count
FROM program_enrollments
WHERE program_id = 1;

SELECT award_name, award_description
FROM award_types
WHERE award_id = 1;

SELECT program_id, COUNT(*) AS total_inquiries
FROM program_inquiries
GROUP BY program_id;

SELECT p.program_name, (SELECT sc.category_name FROM student_categories sc WHERE sc.category_id = 1) AS category_name
FROM programs p
WHERE p.award_id = 1;

external_knowledge:
- 'ongoing' refers to the programs with an 'active' status;
- 'average length' corresponds to the average duration of the programs in years;
- 'current enrollments' refers to the count of enrollments with an 'active' status.

sql:
SELECT program_id, COUNT(*) AS enrollment_count
FROM program_enrollments
GROUP BY program_id;

SELECT COUNT(DISTINCT program_id) AS ActiveProgramsEnrolledLastYear
FROM program_enrollments
WHERE enrollment_date >= DATE('now', '-1 year') AND status = 'active';

SELECT category_name
FROM student_categories
WHERE category_description = 'Students from outside the United Kingdom and European Union';

SELECT category_name, category_description
FROM student_categories
WHERE category_id = 1;
